import React from 'react'

export const Register = () => {
  return (
    <div className='register flex background text-[40px] w-[80%] h-[450px] bg-opacity-75 bg-white rounded-md'>
        <div className='content w-[55%] h-full opacity-100'>
            Register
        </div>
        <div className='logo w-[45%] h-full opacity-100'>
            <img className='w-full h-full rounded-md' src="./requiredfiles/register.png" alt="" />
        </div>
    </div>
  )
}
